import{getSupabase}from './supabase.js';let cachedSettings=null;let cacheTime=0;export async function getGlobalSettings(){const now=Date.now();if(cachedSettings&&(now-cacheTime)<60000){return cachedSettings;}const supabase=await getSupabase();const defaults={global_ads_enabled:true};if(!supabase){return defaults;}try{const{data,error}=await supabase .from('site_settings').select('value').eq('key','global_config').maybeSingle();if(!error&&data&&data.value){cachedSettings=data.value;cacheTime=now;return cachedSettings;}}catch(e){console.warn("[Settings]La tabla site_settings no está lista. Usando fallback...",e);}try{const{data:adminProfile,error:adminError}=await supabase .from('profiles').select('bio').eq('is_admin',true).order('created_at',{ascending:true}).limit(1).maybeSingle();if(!adminError&&adminProfile&&adminProfile.bio){const bioStr=adminProfile.bio.trim();if(bioStr.startsWith('{')&&bioStr.endsWith('}')){const parsed=JSON.parse(bioStr);cachedSettings=parsed;cacheTime=now;return cachedSettings;}}}catch(e){console.error("[Settings]Error en fallback de perfiles:",e);}cachedSettings=defaults;cacheTime=now;return defaults;}export async function saveGlobalSettings(settings){const supabase=await getSupabase();if(!supabase)throw new Error("Supabase no está configurado.");let savedSuccessfully=false;try{const{error}=await supabase .from('site_settings').upsert({key:'global_config',value:settings,updated_at:new Date().toISOString()});if(!error){savedSuccessfully=true;}}catch(e){console.warn("[Settings]Error al guardar en site_settings,intentando fallback:",e);}try{const{data:{user},error:userError}=await supabase.auth.getUser();if(!userError&&user){const{error:profileError}=await supabase .from('profiles').update({bio:JSON.stringify(settings),updated_at:new Date().toISOString()}).eq('id',user.id);if(profileError){if(!savedSuccessfully)throw profileError;}else{savedSuccessfully=true;}}}catch(e){console.error("[Settings]Falló el guardado en el perfil de administrador:",e);if(!savedSuccessfully)throw e;}cachedSettings=settings;cacheTime=Date.now();}